// Signals came through List Existing Pipeline Companies -> here via $input
// List Recent High Signals output is upstream - access via $('List Recent High Signals')
const existingSet = new Set(
  $input.all()
    .map(i => {
      const f = i.json.fields || i.json;
      return ((f['fldLL2FMn3Y3KSG1z'] || f['Company'] || '') + '').toLowerCase().trim();
    })
    .filter(Boolean)
);

const signals = $('List Recent High Signals').all();
const seen = new Set();
const out = [];

for (const item of signals) {
  const f = item.json.fields || item.json;
  const company = ((f['Company'] || '') + '').trim();
  const key = company.toLowerCase();
  if (!company || key === 'unknown' || key === 'multiple developers') continue;
  if (existingSet.has(key) || seen.has(key)) continue;
  seen.add(key);
  out.push({
    json: {
      signal_id: item.json.id,
      signal_company: company,
      signal_type: (f['Signal Type']?.name || f['Signal Type'] || ''),
      signal_detail: (f['Signal Detail'] || ''),
      signal_location: (f['Location'] || ''),
      signal_outreach_angle: (f['Outreach Angle'] || ''),
      signal_score: (f['Score'] || ''),
      signal_mw: (f['MW Size'] || ''),
      actionability: (f['Actionability'] || ''),
      actionability_rationale: (f['Actionability Rationale'] || '')
    }
  });
}

return out;

